-- Replace dummy seed jobs with curated WebMasters + WasaaChat job posts.
-- Soft-closes existing jobs at both companies (preserves applications) then
-- inserts the same ~38 roles at each company (~76 total), each with
-- department-themed cover images, full descriptions, requirements,
-- salary bands, locations and the standard 5-stage hiring pipeline.

-- 1. Soft-close existing jobs at WebMasters + WasaaChat (keeps applications intact)
UPDATE "Job" SET status = 'CLOSED', "updatedAt" = NOW()
WHERE "companyId" IN ('cmol8q1wk0004u7bij7ss2gop', 'cmol8q2hs0007u7bio6o91pic')
  AND id NOT LIKE 'seed-real-%'
  AND status <> 'CLOSED';

-- 2. Insert curated jobs. Idempotent via ON CONFLICT (id) DO NOTHING.
INSERT INTO "Job" (
  id, "companyId", "postedById", title, description, requirements,
  "jobType", location, "salaryMin", "salaryMax", currency, status,
  vacancies, "expiresAt", "createdAt", "updatedAt", "posterUrl", "hiringStages"
) VALUES
  ('seed-real-wm-ceo', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Chief Executive Officer (CEO)', 'Set company direction, drive revenue and growth, make high-impact decisions, own key partnerships and capital allocation. Reports to the Board.', '12+ years building consumer or fintech platforms. Repeat founder or P&L-owning leader. Strong fundraising network. Track record scaling teams beyond 100.', 'FULL_TIME', 'Nairobi, Kenya', 1200000, 2500000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1551836022-deb4988cc6c0?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-coo', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Chief Operating Officer (COO)', 'Own execution across all teams. Run the weekly operating cadence, enforce accountability, remove blockers and manage the reporting system that the CEO and Board rely on.', '10+ years operating role at scale. Deep cross-functional command. Strong KPI discipline. Comfort with both BPO-style ops and product execution.', 'FULL_TIME', 'Nairobi, Kenya', 900000, 1800000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1551836022-deb4988cc6c0?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-cto', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Chief Technology Officer (CTO)', 'Own engineering systems and infrastructure across backend, frontend, mobile and DevOps. Ensure scalability and uptime. Approve all TDD documents and the release process.', '12+ years building large-scale consumer platforms. Hands-on with at least one of: distributed systems, real-time chat, payments. Has scaled engineering teams past 30.', 'FULL_TIME', 'Nairobi, Kenya', 900000, 1800000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-cpo', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Chief Product Officer (CPO)', 'Own product strategy and the feature roadmap. Align product with monetisation. Manage PMs and UX. Approve all SRS documents.', '10+ years senior product leadership. Strong design taste. Track record on retention, monetisation and engagement metrics.', 'FULL_TIME', 'Nairobi, Kenya', 800000, 1600000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1552664730-d307ca884978?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-cfo', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Chief Financial Officer (CFO)', 'Own financial planning and burn rate. Track P&L per business unit, manage payments and compliance, produce weekly and monthly reports for leadership and investors.', 'Qualified accountant (CPA / ACCA / CFA). 10+ years in finance leadership. Experience with fintech, payments, compliance and fundraising preferred.', 'FULL_TIME', 'Nairobi, Kenya', 800000, 1500000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-cgo', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Chief Growth Officer (CGO)', 'Own user acquisition and engagement, drive Wasaa Stars and creator onboarding, build viral and referral loops, responsible for DAU and MAU growth.', '8+ years senior growth leadership in consumer / social products. Deep paid acquisition and viral mechanics expertise. Has owned a CAC budget at scale.', 'FULL_TIME', 'Nairobi, Kenya', 700000, 1400000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-cro', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Chief Revenue Officer (CRO)', 'Own all monetisation streams, hit revenue targets across products. Oversee Ads, Coins, Marketplace and Subscriptions, set pricing governance and report to CEO weekly.', '10+ years owning revenue at a consumer or marketplace platform. Strong on pricing, partnerships and monetisation experimentation.', 'FULL_TIME', 'Nairobi, Kenya', 800000, 1500000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-crisk', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Chief Risk Officer', 'Own enterprise risk: payments fraud, content moderation, data privacy, regulatory and operational risk. Define controls, run audits, and brief the Board.', '10+ years risk leadership in fintech, banking or platform companies. Deep regulatory familiarity (CBK, KICA, GDPR-equivalent).', 'FULL_TIME', 'Nairobi, Kenya', 700000, 1300000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1505664194779-8beaceb93744?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-eng-lead', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Engineering Lead / Head of Engineering', 'Lead all engineering execution. Enforce SRS to TDD to build to release workflow, set sprint targets, ensure code quality and reviews, and coach senior engineers.', '10+ years engineering, 3+ leading teams. Strong in at least two of: distributed backend, mobile, web. Comfortable owning sprint delivery and incident response.', 'FULL_TIME', 'Nairobi, Kenya', 500000, 800000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-be-senior', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Backend Engineer (Senior)', 'Build core APIs, the chat system, payments and ads backend. Ensure scalability and performance, integrate third-party services, mentor mid engineers.', '5+ years building production backends. Strong with Node.js / TypeScript or Go, PostgreSQL, Redis, message queues. Experience scaling beyond 100k users.', 'FULL_TIME', 'Nairobi, Kenya', 280000, 480000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-be-mid', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Backend Engineer (Mid-level)', 'Implement backend features and bug fixes. Write unit and integration tests. Support senior engineers on architecture and design reviews.', '2-4 years backend experience. Strong fundamentals in REST / GraphQL, databases, testing. Eager to learn distributed systems.', 'FULL_TIME', 'Nairobi, Kenya', 150000, 280000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-fe-web', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Frontend Engineer (Web)', 'Build web dashboards: Ads Manager, Creator Portal, internal tools. Ensure responsive performant UI. Implement designs from UX, work closely with backend on APIs.', '4+ years React / Next.js. Strong on accessibility, performance and design system thinking. TypeScript fluent.', 'FULL_TIME', 'Nairobi, Kenya', 220000, 420000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-mobile', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Mobile Engineer (Flutter)', 'Build and maintain the Flutter app on iOS and Android. Implement all mobile features, optimise performance, and own crash-free release quality.', '4+ years Flutter / Dart in production. Comfortable with platform channels, local storage, push notifications, and CI for mobile.', 'FULL_TIME', 'Nairobi, Kenya', 250000, 450000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-devops', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'DevOps / Infrastructure Engineer', 'Manage CI/CD pipelines, Docker and Kubernetes orchestration, cloud infrastructure on AWS or GCP, monitor uptime and autoscaling, on-call coverage.', '4+ years DevOps / SRE. Kubernetes in production. Strong with one cloud (AWS / GCP). Observability with Prometheus, Grafana, Loki / ELK.', 'FULL_TIME', 'Nairobi, Kenya', 280000, 500000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-qa', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'QA Engineer', 'Run functional, integration and load testing. Approve releases. Document bugs. Enforce the no-release-without-QA rule across teams.', '3+ years QA. Both manual and automation experience (Cypress, Playwright, or similar). Mobile testing experience a plus.', 'FULL_TIME', 'Nairobi, Kenya', 180000, 320000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-secops', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Cyber Security Engineer', 'Secure systems and infrastructure. Implement and enforce security controls, conduct vulnerability assessments and pen tests, monitor for threats and respond to incidents.', '5+ years application or infrastructure security. Hands-on with OWASP top 10, cloud security (IAM, VPC), and incident response. Relevant certs welcomed.', 'FULL_TIME', 'Nairobi, Kenya', 320000, 600000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1550751827-4bd374c3f58b?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-ml', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'ML / AI Engineer', 'Build and deploy ML models. Integrate AI features into the platform: recommendation, chat intelligence, moderation. Optimise model performance and own data pipelines.', '4+ years ML engineering. Strong Python, PyTorch / TensorFlow, and at least one production model behind your name. LLM / RAG experience a plus.', 'FULL_TIME', 'Nairobi, Kenya', 320000, 600000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1677442136019-21780ecad995?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-uxui', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'UX / UI Designer', 'Design user flows for all platform features. Improve onboarding conversion. Create mockups for SRS approval. Maintain the design system.', '4+ years product design at a consumer app. Strong portfolio. Figma fluent. Comfortable shipping in tight cycles.', 'FULL_TIME', 'Nairobi, Kenya', 180000, 350000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1559028012-481c04fa702d?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-pmo-head', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Head of PMO', 'Run the program-management office across product, design and engineering. Standardise SRS to TDD to release. Run weekly cross-functional reviews and risk register.', '8+ years senior PM or PMO leadership. Strong process discipline, stakeholder management and prioritisation under pressure.', 'FULL_TIME', 'Nairobi, Kenya', 450000, 750000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1552664730-d307ca884978?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-pm-core', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Product Manager - Core Platform', 'Define features for the feed, chat, messaging and Wasaa Stars. Write SRS documents, align with growth and revenue, coordinate releases across squads.', '4+ years PM at a consumer platform. Track record on engagement metrics. Strong written communication and SRS discipline.', 'FULL_TIME', 'Nairobi, Kenya', 280000, 480000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1552664730-d307ca884978?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wm-pm-mon', 'cmol8q1wk0004u7bij7ss2gop', '9a6f7ade-3f39-43a1-9b4c-5348b5fdeada', 'Product Manager - Monetisation', 'Own Coins, Ads Manager, Marketplace and Dating product specs. Ensure every feature has a clear revenue path. Run A/B pricing experiments and conversion funnels.', '4+ years PM with a monetisation focus. Strong analytics, pricing and experimentation muscles.', 'FULL_TIME', 'Nairobi, Kenya', 280000, 480000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
