  ('seed-real-wc-cfo', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'Chief Financial Officer (CFO)', 'Own financial planning and burn rate. Track P&L per business unit, manage payments and compliance, produce weekly and monthly reports for leadership and investors.', 'Qualified accountant (CPA / ACCA / CFA). 10+ years in finance leadership. Experience with fintech, payments, compliance and fundraising preferred.', 'FULL_TIME', 'Nairobi, Kenya', 800000, 1500000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
