  ('seed-real-wc-cro', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'Chief Revenue Officer (CRO)', 'Own all monetisation streams, hit revenue targets across products. Oversee Ads, Coins, Marketplace and Subscriptions, set pricing governance and report to CEO weekly.', '10+ years owning revenue at a consumer or marketplace platform. Strong on pricing, partnerships and monetisation experimentation.', 'FULL_TIME', 'Nairobi, Kenya', 800000, 1500000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-crisk', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'Chief Risk Officer', 'Own enterprise risk: payments fraud, content moderation, data privacy, regulatory and operational risk. Define controls, run audits, and brief the Board.', '10+ years risk leadership in fintech, banking or platform companies. Deep regulatory familiarity (CBK, KICA, GDPR-equivalent).', 'FULL_TIME', 'Nairobi, Kenya', 700000, 1300000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1505664194779-8beaceb93744?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-eng-lead', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'Engineering Lead / Head of Engineering', 'Lead all engineering execution. Enforce SRS to TDD to build to release workflow, set sprint targets, ensure code quality and reviews, and coach senior engineers.', '10+ years engineering, 3+ leading teams. Strong in at least two of: distributed backend, mobile, web. Comfortable owning sprint delivery and incident response.', 'FULL_TIME', 'Nairobi, Kenya', 500000, 800000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-be-senior', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'Backend Engineer (Senior)', 'Build core APIs, the chat system, payments and ads backend. Ensure scalability and performance, integrate third-party services, mentor mid engineers.', '5+ years building production backends. Strong with Node.js / TypeScript or Go, PostgreSQL, Redis, message queues. Experience scaling beyond 100k users.', 'FULL_TIME', 'Nairobi, Kenya', 280000, 480000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-be-mid', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'Backend Engineer (Mid-level)', 'Implement backend features and bug fixes. Write unit and integration tests. Support senior engineers on architecture and design reviews.', '2-4 years backend experience. Strong fundamentals in REST / GraphQL, databases, testing. Eager to learn distributed systems.', 'FULL_TIME', 'Nairobi, Kenya', 150000, 280000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-fe-web', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'Frontend Engineer (Web)', 'Build web dashboards: Ads Manager, Creator Portal, internal tools. Ensure responsive performant UI. Implement designs from UX, work closely with backend on APIs.', '4+ years React / Next.js. Strong on accessibility, performance and design system thinking. TypeScript fluent.', 'FULL_TIME', 'Nairobi, Kenya', 220000, 420000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-mobile', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'Mobile Engineer (Flutter)', 'Build and maintain the Flutter app on iOS and Android. Implement all mobile features, optimise performance, and own crash-free release quality.', '4+ years Flutter / Dart in production. Comfortable with platform channels, local storage, push notifications, and CI for mobile.', 'FULL_TIME', 'Nairobi, Kenya', 250000, 450000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-devops', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'DevOps / Infrastructure Engineer', 'Manage CI/CD pipelines, Docker and Kubernetes orchestration, cloud infrastructure on AWS or GCP, monitor uptime and autoscaling, on-call coverage.', '4+ years DevOps / SRE. Kubernetes in production. Strong with one cloud (AWS / GCP). Observability with Prometheus, Grafana, Loki / ELK.', 'FULL_TIME', 'Nairobi, Kenya', 280000, 500000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-qa', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'QA Engineer', 'Run functional, integration and load testing. Approve releases. Document bugs. Enforce the no-release-without-QA rule across teams.', '3+ years QA. Both manual and automation experience (Cypress, Playwright, or similar). Mobile testing experience a plus.', 'FULL_TIME', 'Nairobi, Kenya', 180000, 320000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-secops', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'Cyber Security Engineer', 'Secure systems and infrastructure. Implement and enforce security controls, conduct vulnerability assessments and pen tests, monitor for threats and respond to incidents.', '5+ years application or infrastructure security. Hands-on with OWASP top 10, cloud security (IAM, VPC), and incident response. Relevant certs welcomed.', 'FULL_TIME', 'Nairobi, Kenya', 320000, 600000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1550751827-4bd374c3f58b?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
  ('seed-real-wc-ml', 'cmol8q2hs0007u7bio6o91pic', '46557841-a9d2-4291-9da5-1a8cc83af802', 'ML / AI Engineer', 'Build and deploy ML models. Integrate AI features into the platform: recommendation, chat intelligence, moderation. Optimise model performance and own data pipelines.', '4+ years ML engineering. Strong Python, PyTorch / TensorFlow, and at least one production model behind your name. LLM / RAG experience a plus.', 'FULL_TIME', 'Nairobi, Kenya', 320000, 600000, 'KES', 'ACTIVE', 1, NOW() + INTERVAL '60 days', NOW(), NOW(), 'https://images.unsplash.com/photo-1677442136019-21780ecad995?w=1200&h=630&fit=crop&q=80', '[{"order": 1, "name": "Application Review", "description": "Initial screening of applications"}, {"order": 2, "name": "Phone / Video Screen", "description": "Short 15-30 min introductory call"}, {"order": 3, "name": "Technical / Domain Interview", "description": "Deep-dive on skills and domain fit"}, {"order": 4, "name": "Final Interview", "description": "Meet senior leadership and the team"}, {"order": 5, "name": "Offer", "description": "Extend offer and onboarding"}]'::jsonb),
